"use client"

import * as React from "react"
import Link from "next/link"
import { Menu, X } from "lucide-react"

const LINKS = ["Classes", "Schedule", "Studio", "Journal"]

/**
 * Studio header — an airy serif wordmark with quiet sans nav and a blush CTA.
 */
export function HeaderStudio() {
  const [open, setOpen] = React.useState(false)

  return (
    <header className="border-b border-border bg-background text-foreground">
      <div className="mx-auto flex max-w-6xl items-center justify-between px-6 py-5 sm:px-10">
        <Link href="#" className="font-serif text-2xl tracking-tight">
          Méthode
        </Link>

        <nav className="hidden items-center gap-9 md:flex">
          {LINKS.map((l) => (
            <Link key={l} href="#" className="text-sm text-muted-foreground transition-colors hover:text-foreground">
              {l}
            </Link>
          ))}
        </nav>

        <div className="flex items-center gap-4">
          <Link
            href="#"
            className="hidden rounded-full bg-primary px-6 py-2.5 text-sm font-medium text-primary-foreground transition-opacity hover:opacity-90 sm:block"
          >
            Book a class
          </Link>
          <button onClick={() => setOpen((o) => !o)} aria-label="Menu" className="text-foreground md:hidden">
            {open ? <X className="size-5" /> : <Menu className="size-5" />}
          </button>
        </div>
      </div>

      {open && (
        <nav className="grid gap-1 border-t border-border px-6 py-4 md:hidden">
          {LINKS.map((l) => (
            <Link key={l} href="#" className="py-2 text-sm text-muted-foreground hover:text-foreground">
              {l}
            </Link>
          ))}
        </nav>
      )}
    </header>
  )
}

const ROWS = [
  {
    kicker: "Strength",
    title: "Build it slowly, keep it longer",
    body: "Spring resistance meets controlled tempo. You leave stronger without the strain — the kind of strength that lasts past the soreness.",
    points: ["Progressive loading", "Joint-friendly", "Posture-first"],
  },
  {
    kicker: "Calm",
    title: "A reset for your nervous system",
    body: "Soft light, quiet rooms, breath-led movement. Most members tell us the calm is the part they can't go without.",
    points: ["Breath cues throughout", "No mirrors, no rush", "Phone-free floor"],
  },
]

/**
 * Studio features — alternating airy rows with a soft media panel and checklist.
 */
export function FeatureStudio() {
  return (
    <section className="bg-background px-6 py-20 text-foreground sm:px-10 sm:py-28">
      <div className="mx-auto max-w-6xl space-y-20">
        {ROWS.map((r, i) => (
          <div
            key={r.title}
            className={`grid items-center gap-10 lg:grid-cols-2 lg:gap-16 ${
              i % 2 === 1 ? "lg:[&>*:first-child]:order-2" : ""
            }`}
          >
            <div>
              <p className="text-xs tracking-[0.25em] uppercase text-primary">{r.kicker}</p>
              <h3 className="mt-3 font-serif text-3xl leading-tight tracking-tight">{r.title}</h3>
              <p className="mt-4 leading-relaxed text-muted-foreground">{r.body}</p>
              <ul className="mt-6 space-y-3">
                {r.points.map((p) => (
                  <li key={p} className="flex items-center gap-3 text-sm">
                    <span className="size-1.5 rounded-full bg-primary" />
                    {p}
                  </li>
                ))}
              </ul>
            </div>
            <div className="relative aspect-[5/4] overflow-hidden rounded-[1.5rem] bg-secondary">
              <div className="absolute inset-0 bg-[radial-gradient(circle_at_50%_40%,rgba(201,142,134,0.3),transparent_60%)]" />
            </div>
          </div>
        ))}
      </div>
    </section>
  )
}

"use client"

import { useRef } from "react"
import { motion, useScroll, useTransform } from "framer-motion"

/**
 * Studio parallax — a calm serif statement with soft blush washes drifting on scroll.
 */
export function ParallaxStudio() {
  const ref = useRef<HTMLDivElement>(null)
  const { scrollYProgress } = useScroll({ target: ref, offset: ["start end", "end start"] })

  const y1 = useTransform(scrollYProgress, [0, 1], ["-15%", "15%"])
  const y2 = useTransform(scrollYProgress, [0, 1], ["12%", "-12%"])

  return (
    <section
      ref={ref}
      className="relative grid min-h-[440px] place-items-center overflow-hidden bg-secondary px-6 py-24 text-foreground"
    >
      <motion.div
        aria-hidden
        style={{ y: y1 }}
        className="pointer-events-none absolute -left-20 top-0 size-[28rem] rounded-full bg-[radial-gradient(circle,rgba(201,142,134,0.28),transparent_65%)]"
      />
      <motion.div
        aria-hidden
        style={{ y: y2 }}
        className="pointer-events-none absolute -right-16 bottom-0 size-[24rem] rounded-full bg-[radial-gradient(circle,rgba(217,194,184,0.5),transparent_65%)]"
      />

      <div className="relative max-w-3xl text-center">
        <p className="text-xs tracking-[0.25em] uppercase text-muted-foreground">Our philosophy</p>
        <h2 className="mt-5 font-serif text-[clamp(2rem,6vw,4.25rem)] leading-[1.08] tracking-tight text-balance">
          Strength is quiet. So is the way we teach it.
        </h2>
      </div>
    </section>
  )
}

import { Check } from "lucide-react"

const PLANS = [
  {
    name: "Intro",
    price: "39",
    unit: "/ 2 weeks",
    blurb: "New here? Start gently.",
    points: ["3 classes", "Any time, any class", "Mat loan included"],
    featured: false,
  },
  {
    name: "Unlimited",
    price: "180",
    unit: "/ month",
    blurb: "For a steady practice.",
    points: ["Unlimited classes", "Priority booking", "10% off the shop", "Guest pass monthly"],
    featured: true,
  },
  {
    name: "Eight pack",
    price: "200",
    unit: "/ 8 classes",
    blurb: "Move at your own rhythm.",
    points: ["8 classes, 3-month validity", "Shareable with a friend", "No commitment"],
    featured: false,
  },
]

/**
 * Studio memberships — soft rounded plan cards; the featured one in blush.
 */
export function PricingStudio() {
  return (
    <section className="bg-background px-6 py-20 text-foreground sm:px-10 sm:py-28">
      <div className="mx-auto max-w-6xl">
        <div className="mx-auto max-w-xl text-center">
          <p className="text-xs tracking-[0.25em] uppercase text-primary">Memberships</p>
          <h2 className="mt-4 font-serif text-[clamp(2rem,5vw,3.5rem)] leading-[1.05] tracking-tight">
            Find your rhythm
          </h2>
        </div>

        <div className="mt-12 grid items-start gap-6 md:grid-cols-3">
          {PLANS.map((p) => (
            <div
              key={p.name}
              className={`flex flex-col rounded-[1.5rem] p-7 ${
                p.featured ? "bg-primary text-primary-foreground" : "border border-border bg-card"
              }`}
            >
              <div className="flex items-center justify-between">
                <p className="font-serif text-xl">{p.name}</p>
                {p.featured && (
                  <span className="rounded-full bg-primary-foreground/15 px-3 py-0.5 text-[11px] tracking-[0.15em] uppercase">
                    Popular
                  </span>
                )}
              </div>
              <p className={`mt-1.5 text-sm ${p.featured ? "text-primary-foreground/80" : "text-muted-foreground"}`}>
                {p.blurb}
              </p>
              <p className="mt-6 font-serif text-4xl tracking-tight">
                ${p.price}
                <span className={`text-base ${p.featured ? "text-primary-foreground/70" : "text-muted-foreground"}`}>
                  {" "}{p.unit}
                </span>
              </p>
              <ul className="mt-6 flex-1 space-y-3">
                {p.points.map((pt) => (
                  <li key={pt} className="flex items-start gap-3 text-sm">
                    <Check className={`mt-0.5 size-4 shrink-0 ${p.featured ? "text-primary-foreground" : "text-primary"}`} />
                    {pt}
                  </li>
                ))}
              </ul>
              <button
                className={`mt-7 rounded-full py-3 text-sm font-medium transition-opacity hover:opacity-90 ${
                  p.featured ? "bg-primary-foreground text-primary" : "bg-primary text-primary-foreground"
                }`}
              >
                Choose {p.name}
              </button>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
